+
+function useProjectState(): [
+  ProjectDocument,
+  (updater: (project: ProjectDocument) => ProjectDocument) => void,
+  SavedProject[],
+  (label: string) => void,
+  (project: ProjectDocument) => void,
+  (id: string) => void
+] {
+  const [project, setProject] = useState<ProjectDocument>(() => {
+    const loaded = loadAutosave();
+    const theme = loadTheme();
+    return {
+      ...loaded,
+      theme: theme ?? loaded.theme
+    };
+  });
+  const [saves, setSaves] = useState<SavedProject[]>(() => loadNamedSaves());
+
+  useEffect(() => {
+    saveAutosave(project);
+  }, [project]);
+
+  useEffect(() => {
+    saveTheme(project.theme);
+    applyTheme(project.theme);
+  }, [project.theme]);
+
+  const updateProject = (updater: (project: ProjectDocument) => ProjectDocument) => {
+    setProject((current) => updater(current));
+  };
+
+  const handleCreateSave = (label: string) => {
+    setSaves(createNamedSave(project, label));
+  };
+
+  const handleLoadSave = (next: ProjectDocument) => {
+    setProject(next);
+  };
+
+  const handleDeleteSave = (id: string) => {
+    setSaves(deleteNamedSave(id));
+  };
