+  const { project, updateProject } = props;
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const rendererRef = useRef<CARenderer | undefined>(undefined);
+  const rafRef = useRef<number | undefined>(undefined);
+  const accumulatorRef = useRef(0);
+  const lastRef = useRef<number | undefined>(undefined);
+
+  useEffect(() => {
+    if (!canvasRef.current) {
+      return;
+    }
+    if (!rendererRef.current) {
+      rendererRef.current = new CARenderer(canvasRef.current, project.ca);
+      rendererRef.current.randomize();
+    } else {
+      rendererRef.current.configure(project.ca);
+    }
+    rendererRef.current.render();
+  }, [project.ca]);
+
+  useEffect(() => {
+    const tick = (timestamp: number) => {
+      const last = lastRef.current ?? timestamp;
+      lastRef.current = timestamp;
+      const delta = timestamp - last;
+      accumulatorRef.current += delta;
+      const renderer = rendererRef.current;
+      if (renderer && project.ca.isPlaying) {
+        const stepDuration = 1000 / Math.max(project.ca.stepsPerSecond, 1);
+        while (accumulatorRef.current >= stepDuration) {
