function MandelbrotSelectorCanvas(props: {
  canvasRef: preact.RefObject<HTMLCanvasElement>;
  resizeHandleRef: preact.RefObject<HTMLButtonElement>;
  selector: ProjectDocument["mandelbrotSelector"];
  selectedComplex: { re: number; im: number } | undefined;
  onViewportChange: (patch: Partial<ProjectDocument["mandelbrotSelector"]>) => void;
  onComplexSelect: (complex: { re: number; im: number }) => void;
  onHoverChange: (complex: { re: number; im: number } | undefined) => void;
}): JSX.Element {
  const {
    canvasRef,
    resizeHandleRef,
    selector,
    onViewportChange,
    onComplexSelect,
