      }
      const rect = canvas.getBoundingClientRect();
      if (event.target === canvas || drag) {
        const complex = screenToComplex(
          selector,
          { width: rect.width, height: rect.height },
          event.clientX - rect.left,
          event.clientY - rect.top
        );
        onHoverChange(complex);
      }
      if (!drag) {
        return;
      }
      if (drag.mode === "pan") {
        const dx = event.clientX - drag.startX;
        const dy = event.clientY - drag.startY;
        const scale = selector.zoom * Math.max(rect.height, 1);
        onViewportChange({
          centerRe: drag.startCenterRe - (dx / scale) * (rect.width / rect.height),
          centerIm: drag.startCenterIm + dy / scale
        });
        drag.moved = true;
      } else {
        onViewportChange({
          width: clamp(drag.startWidth + (event.clientX - drag.startX), 280, 760),
          height: clamp(drag.startHeight + (event.clientY - drag.startY), 220, 560)
        });
        drag.moved = true;
