      window.removeEventListener("pointermove", handlePointerMove);
      window.removeEventListener("pointerup", handlePointerUp);
    };
  }, [canvasRef, onHoverChange, onViewportChange, selector]);

  return (
    <div
      className="mandelbrot-stage"
      style={{
        width: `${selector.width}px`,
        height: `${selector.height}px`
      }}
    >
      <canvas
        ref={canvasRef}
        onPointerDown={(event) => {
          const canvas = canvasRef.current;
          if (!canvas) {
            return;
          }
          dragStateRef.current = {
            mode: "pan",
            startX: event.clientX,
            startY: event.clientY,
            startCenterRe: selector.centerRe,
            startCenterIm: selector.centerIm,
            startWidth: selector.width,
            startHeight: selector.height,
            moved: false
          };
        }}
        onPointerUp={(event) => {
          const canvas = canvasRef.current;
          const drag = dragStateRef.current;
          if (!canvas || !drag || drag.mode !== "pan") {
